{"content":"1: using System;
2: using System.Collections.Generic;
3: using System.Linq;
4: using System.Text;
5: using Microsoft.DotNet.Cli.Utils;
6: 
7: namespace DotNetKoans.Engine
8: {
9:     public class Sensei
10:     {
11:         private Reporter Console;
12:         private ICollection<StepResult> Observations;
13: 
14:         public Sensei(Reporter console)
15:         {
16:             Console = console;
17:             Observations = new List<StepResult>();
18:         }
19: 
20:         public bool Failed()
21:         {
22:             return Observations.Any(s => s is FailedStepResult);
23:         }
24: 
25:         public void Observe(StepResult result)
26:         {
27:             Observations.Add(result);
28:             if (result.IsFailure)
29:             {
30:                 throw new SenseiException();
31:             }
32:         }
33: 
34:         public void Instruct(Path path)
35:         {
36:             if (Failed())
37:             {
38:                 foreach (var result in Observations)
39:                 {
40:                     result.Report(Console);
41:                 }
42:                 Encourage();
43:                 GuideThroughError();
44:                 AZenlikeStatement();
45:                 Console.WriteLine();
46:                 ShowProgressOn(path);
47:             }
48:             else
49:             {
50:                 EndScreen();
51:             }
52:         }
53: 
54:         public void Encourage()
55:         {
56:             Console.WriteLine(string.Empty);
57:             Console.WriteLine("The Master says:");
58:             Console.WriteLine("  You have not yet reached enlightenment.".Cyan());
59:         }
60: 
61:         private void GuideThroughError()
62:         {
63: 
64:         }
65: 
66:         private void AZenlikeStatement()
67:         {
68:             Random rand = new Random(DateTime.Now.Millisecond);
69: 
70:             // Quotes from http://www.zen-buddhism.net/quotes/zen-quotes.html
71:             List<string> statements = new List<string> {
72:                 "You should study not only that you become a mother when your child is born, but also that you become a child.",
73:                 "The one who is good at shooting does not hit the center of the target.",
74:                 "When an ordinary man attains knowledge, he is a sage; when a sage attains understanding, he is an ordinary man.",
75:                 "Think with your whole body.",
76:                 "What is the sound of one hand clapping?",
77:                 "I come to realize that mind is no other than mountains and rivers and the great wide earth, the sun and the moon and stars.",
78:                 "In a mind clear as still water, even the waves, breaking, are reflecting its light.",
79:                 "You will not be punished for your anger; you will be punished by your anger.",
80:                 "Zen is not some kind of excitement, but concentration on our usual everyday routine.",
81:                 "Before enlightenment; chop wood, carry water. After enlightenment; chop wood, carry water.",
82:                 "You cannot travel the path until you have become the path itself",
83:                 "You only lose what you cling to.",
84:                 "Doubt everything. Find your own light.",
85:                 "It is a man's own mind, not his enemy or foe, that lures him to evil ways"
86:             };
87: 
88:             Console.WriteLine(String.Format("  \"{0}\"", statements[rand.Next(statements.Count())]));
89:         }
90: 
91:         private void ShowProgressOn(Path path)
92:         {
93: 
94:             int stepCount = 0;
95:             path.ForEachStep(s => stepCount++);
96:             int stepsNotCompleted = stepCount - Observations.Count(o => o.IsSuccess);
97: 
98:             var graph = GenerateGraph(stepCount - stepsNotCompleted, stepCount);
99: 
100:             Console.WriteLine(graph.Green());
101:             Console.WriteLine($"  {stepsNotCompleted} of {stepCount} steps remain on the path.".Green());
102:         }
103: 
104:         private string GenerateGraph(int completed, int all, int scale = 60)
105:         {
106:             int stepCompletedRatio = completed == 0 ? 1 : (int)Math.Round(((float)completed / (float)all) * scale);
107: 
108:             var sb = new StringBuilder();
109:             sb.Append("  [");
110:             sb.Append('#', stepCompletedRatio);
111:             sb.Append('_', scale - stepCompletedRatio);
112:             sb.Append(']');
113: 
114:             return sb.ToString();
115:         }
116: 
117:         private void EndScreen()
118:         {
119:             Console.WriteLine(string.Empty);
120:             Console.WriteLine("The Master says:");
121:             Console.WriteLine("  You have reached enlightenment.".Cyan());
122:         }
123:     }
124: 
125:     public class SenseiException : Exception { }
126: }","url":"https://sourcegraph.sourcegraph.com/github.com/sg-benchmarks/DotNetKoans--dibench@dfc61171effb00d16ea1e4bd7bd44e2eced84484/-/blob/Engine/Sensei.cs"}

{"content":"1: using System;
2: using System.Linq;
3: using System.Reflection;
4: using Microsoft.DotNet.Cli.Utils;
5: using Xunit.Sdk;
6: 
7: namespace DotNetKoans.Engine
8: {
9:     public class Step
10:     {
11: 
12:         public Step(TypeInfo typeInfo, MethodInfo methodInfo)
13:         {
14:             TypeInfo = typeInfo;
15:             MethodInfo = methodInfo;
16:         }
17: 
18:         public TypeInfo TypeInfo { get; }
19:         public MethodInfo MethodInfo { get; }
20: 
21:         public string Name { get { return $"{TypeInfo.Name} {MethodInfo.Name}"; } }
22:         public StepResult Meditate()
23:         {
24:             var koan = GetKoan();
25:             var results = new[] {
26:                 Try(() => koan.Setup()),
27:                 Try(() => MethodInfo.Invoke(koan, Array.Empty<object>())),
28:                 Try(() => koan.TearDown())
29:             };
30: 
31:             return results.Any(r => r is FailedStepResult) ?
32:                 results.First(r => r is FailedStepResult) :
33:                 results.FirstOrDefault();
34:         }
35: 
36:         public StepResult Try(Action throwable)
37:         {
38:             try
39:             {
40:                 throwable();
41:             }
42:             catch (TargetInvocationException e)
43:             {
44:                 if (e.InnerException is XunitException)
45:                 {
46:                     return new AssertionFailedStepResult { Step = this, Exception = e.InnerException };
47:                 }
48:                 return new FailedStepResult { Step = this, Exception = e.InnerException ?? e };
49:             }
50:             catch (Exception e)
51:             {
52:                 return new FailedStepResult { Step = this, Exception = e };
53:             }
54: 
55:             return new SuccessStepResult { Step = this };
56:         }
57: 
58:         public Koan Instance { get; private set; }
59: 
60:         public Koan GetKoan()
61:         {
62:             return Instance ?? (Instance = Activator.CreateInstance(TypeInfo.AsType()) as Koan);
63:         }
64:     }
65: 
66:     public abstract class StepResult
67:     {
68:         public bool IsSuccess { get; set; }
69:         public bool IsFailure => !IsSuccess;
70:         public Step Step { get; set; }
71:         public Exception Exception { get; set; }
72: 
73:         public virtual void Report(Reporter console)
74:         {
75:             console.WriteLine($"{Step.Name} has damaged your karma.".Bold().Red());
76:             console.WriteLine();
77: 
78:             if (Exception is AssertActualExpectedException assertException)
79:             {
80:                 console.WriteLine("The truth you are looking for...".Bold().Green());
81:                 console.WriteLine($"{assertException.Actual} is not {assertException.Expected}".Bold().Green());
82:                 console.WriteLine();
83:             }
84: 
85:             console.WriteLine("Ponder the meaning in these lines:".Cyan());
86:             console.WriteLine($"{String.Join('\n', Exception.GetStackTracePaths())}".Cyan());
87:         }
88:     }
89: 
90:     public class SuccessStepResult : StepResult
91:     {
92:         public SuccessStepResult()
93:         {
94:             IsSuccess = true;
95:         }
96: 
97:         public override void Report(Reporter console)
98:         {
99:             console.WriteLine($"{Step.Name} has expanded your awareness.".Green());
100:         }
101:     }
102: 
103:     public class FailedStepResult : StepResult
104:     {
105: 
106:     }
107: 
108:     public class AssertionFailedStepResult : FailedStepResult
109:     { }
110: 
111:     //This attribute is because we can't guarantee the order
112:     //of the methods when we walk a class. So this allows us
113:     //to order them to make sure we evaluate them as intended.
114:     //Note that positioning is relative to the class, not to the
115:     //entire project
116:     public class StepAttribute : Attribute
117:     {
118:         public int Position { get; set; }
119: 
120:         public StepAttribute(int position) { this.Position = position; }
121:     }
122: }","url":"https://sourcegraph.sourcegraph.com/github.com/sg-benchmarks/DotNetKoans--dibench@dfc61171effb00d16ea1e4bd7bd44e2eced84484/-/blob/Engine/Step.cs"}

