7: namespace DotNetKoans.Engine.Tests
8: {
9:     public class StepTests : TestBase
10:     {
11:         [Fact]
12:         public void KoanBuilderShouldBuildCorrectType()
13:         {
14:             var step = new Step(GetTestTypeInfo(), GetTestMethodInfos().First());
15: 
16:             var koan = step.GetKoan();
17: 
18:             Assert.IsType<TestKoan>(koan);
19:             Assert.Same(koan, step.Instance);
20:             Assert.False(step.Instance?.Cast<TestKoan>().WasSetup);
21:             Assert.False(step.Instance?.Cast<TestKoan>().WasToreDown);
22: 
23:         }
24: 
25:         [Fact]
26:         public void StepNameShouldBeBasedOnTypeAndMethod()
27:         {
28:             var step = new Step(GetTestTypeInfo(), GetTestMethodInfos().First());
29: 
30:             Assert.Contains(GetTestTypeInfo().Name, step.Name);
31:             Assert.Contains(GetTestMethodInfos().First().Name, step.Name);
32:             Assert.True(step.Name.IndexOf(GetTestTypeInfo().Name) < step.Name.IndexOf(GetTestMethodInfos().First().Name));
33:         }
34: 
35:         [Fact]
36:         public void PassingStepShouldBeSuccessful()
37:         {
38:             var step = new Step(GetTestTypeInfo(), GetTestMethodInfos().First());
39: 
40:             var result = step.Meditate();
41: 
42:             Assert.IsType<SuccessStepResult>(result);
43:             Assert.Same(step, result.Step);
44:             Assert.True(step.Instance.Cast<TestKoan>().WasSetup, "Koan was unexpectedly setup");
45:             Assert.True(step.Instance.Cast<TestKoan>().WasToreDown, "Koan was unexpectedly tore down");
46:         }
47: 
48:         [Fact]
49:         public void FailingAssertionStepShouldFail()
50:         {
51:             var step = new Step(GetTestTypeInfo(), GetTestMethodInfos()[1]);
52: 
53:             var result = step.Meditate();
54: 
55:             Assert.IsType<AssertionFailedStepResult>(result);
56:             Assert.IsAssignableFrom<XunitException>(result.Cast<AssertionFailedStepResult>().Exception);
57:             Assert.Same(step, result.Step);
58:             Assert.True(step.Instance.Cast<TestKoan>().WasSetup, "Koan was not properly setup");
59:             Assert.True(step.Instance.Cast<TestKoan>().WasToreDown, "Koan was not properly tore down");
60:         }
61: 
62:         [Fact]
63:         public void RandomExceptionStepShouldFail()
64:         {
65:             var step = new Step(GetTestTypeInfo(), GetTestMethodInfos().Last());
66: 
67:             var result = step.Meditate();
68: 
69:             Assert.IsType<FailedStepResult>(result);
70:             Assert.IsAssignableFrom<NotImplementedException>(result.Cast<FailedStepResult>().Exception);
71:             Assert.Same(step, result.Step);
72:             Assert.True(step.Instance.Cast<TestKoan>().WasSetup, "Koan was not properly setup");
73:             Assert.True(step.Instance.Cast<TestKoan>().WasToreDown, "Koan was not properly tore down");
74:         }
75:     }
76: }","url":"https://sourcegraph.sourcegraph.com/github.com/sg-benchmarks/DotNetKoans--dibench@dfc61171effb00d16ea1e4bd7bd44e2eced84484/-/blob/Engine/Tests/StepTests.cs"}

